@startuml
' UML diagram for Reactive Streams Publisher/Subscriber pattern

class Publisher {
  <<interface>>
  +subscribe(Subscriber<? super T> s)
}

class Flowable {
  <<abstract>>
  +subscribeActual(Subscriber<? super T> s)
}

class FlowableFilter {
  <<class>>
  +filter()
}

class FilterSubscriber {
  <<class>>
  +onNext(T item)
  +onError(Throwable t)
  +onComplete()
}

class FlowableMap {
  <<class>>
  +map()
}

class MapSubscriber {
  <<class>>
  +onNext(T item)
  +onError(Throwable t)
  +onComplete()
}

class Subscription {
  <<interface>>
  +request(long n)
  +cancel()
}

' Relationships
Publisher <|.. Flowable
Flowable <|-- FlowableFilter
Flowable <|-- FlowableMap
FlowableFilter o-- FilterSubscriber
FlowableMap o-- MapSubscriber
FilterSubscriber ..> Subscription
MapSubscriber ..> Subscription

' Styling
class Publisher {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class Flowable {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class FlowableFilter {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class FilterSubscriber {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class FlowableMap {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class MapSubscriber {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

class Subscription {
  background-color: #f0f0f0;
  border: 1px solid #333;
}

@enduml
